'use server'
import { createClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import { revalidatePath } from 'next/cache'
import type { EventFormValues } from '@/lib/validations/event'

export async function createEventAction(data: EventFormValues) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return { error: '로그인이 필요합니다' }

  const payload = { ...data, start_at: new Date(data.start_at).toISOString(), end_at: new Date(data.end_at).toISOString(), created_by: user.id }

  const { data: event, error } = await supabase.from('events').insert(payload).select('id').single()
  if (error?.code === '23505') { // unique violation on invite_code
    // retry once: omit invite_code so DB generates new default
    const { data: retryEvent, error: retryError } = await supabase.from('events').insert(payload).select('id').single()
    if (retryError) return { error: retryError.message }
    redirect('/events/' + retryEvent.id)
  }
  if (error) return { error: error.message }
  redirect('/events/' + event.id)
}

export async function updateEventAction(id: string, data: EventFormValues) {
  const supabase = await createClient()
  const payload = { ...data, start_at: new Date(data.start_at).toISOString(), end_at: new Date(data.end_at).toISOString() }
  const { error } = await supabase.from('events').update(payload).eq('id', id)
  if (error) return { error: error.message }
  revalidatePath('/events/' + id)
  redirect('/events/' + id)
}

export async function deleteEventAction(id: string) {
  const supabase = await createClient()
  const { error } = await supabase.from('events').delete().eq('id', id)
  if (error) return { error: error.message }
  redirect('/events')
}
```

