import type { SupabaseClient } from '@supabase/supabase-js'
import { computeEventStatus } from '@/lib/utils'

export async function getMyEvents(supabase: SupabaseClient, userId: string) {
  const [hosted, participated] = await Promise.all([
    supabase.from('events').select('*, participant_count:event_participants(count)').eq('created_by', userId),
    supabase.from('events').select('*, participant_count:event_participants(count)').in('id',
      supabase.from('event_participants').select('event_id').eq('user_id', userId))
  ])
  const allEvents = [...(hosted.data ?? []), ...(participated.data ?? [])]
  const seen = new Set()
  return allEvents.filter(e => { if (seen.has(e.id)) return false; seen.add(e.id); return true })
    .map(e => ({ ...e, participant_count: e.participant_count?.[0]?.count ?? 0, status: computeEventStatus(e.start_at, e.end_at) }))
}

export async function getEventById(supabase: SupabaseClient, id: string) {
  const { data } = await supabase.from('events').select('*, host:profiles!created_by(id,name,avatar_url), participants:event_participants(*, user:profiles(id,name,avatar_url))').eq('id', id).single()
  if (!data) return null
  return { ...data, status: computeEventStatus(data.start_at, data.end_at), participant_count: data.participants?.length ?? 0 }
}

export async function getEventByInviteCode(supabase: SupabaseClient, code: string) {
  const { data } = await supabase.from('events').select('*, participant_count:event_participants(count)').eq('invite_code', code).single()
  if (!data) return null
  return { ...data, participant_count: data.participant_count?.[0]?.count ?? 0, status: computeEventStatus(data.start_at, data.end_at) }
}
```

