export function EventForm({ defaultValues, defaultCoverImageUrl, action }: EventFormProps) {
  const [isPending, startTransition] = useTransition()
  const [serverError, setServerError] = useState<string | null>(null)
  const [coverImageUrl, setCoverImageUrl] = useState<string | null>(defaultCoverImageUrl ?? null)
  const [imageUploading, setImageUploading] = useState(false)

  const handleImageChange = async (e: ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return
    setImageUploading(true)
    const supabase = createClient()
    const fileName = `${Date.now()}-${file.name}`
    const { data, error } = await supabase.storage.from('event-covers').upload(fileName, file)
    if (!error && data) {
      const { data: { publicUrl } } = supabase.storage.from('event-covers').getPublicUrl(data.path)
      setCoverImageUrl(publicUrl)
    }
    setImageUploading(false)
  }

  const onSubmit = form.handleSubmit((data) => {
    setServerError(null)
    startTransition(async () => {
      const result = await action({ ...data, cover_image_url: coverImageUrl ?? undefined })
      if (result?.error) setServerError(result.error)
    })
  })

  // ... 기존 폼 필드 유지
  // 이미지 업로드 필드 추가 (커버 이미지 섹션)
  // 서버 에러 표시 (버튼 위에)
  // 버튼: disabled={isPending || imageUploading}
