import { updateEventAction } from '@/app/actions/events'
import { getEventById } from '@/lib/queries/events'

export default async function EditEventPage({ params }) {
  const { id } = await params
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) redirect('/auth/login')

  const event = await getEventById(supabase, id)
  if (!event) notFound()
  if (event.created_by !== user.id) redirect('/events/' + id)

  const defaultValues = { title: event.title, ... , start_at: event.start_at.slice(0, 16), end_at: event.end_at.slice(0, 16) }
  const boundUpdateAction = updateEventAction.bind(null, id)
  return <EventForm defaultValues={defaultValues} defaultCoverImageUrl={event.cover_image_url} action={boundUpdateAction} />
}
