'use client'
import { useTransition } from 'react'
import { Loader2, UserPlus } from 'lucide-react'

interface JoinEventButtonProps:
  alreadyJoined: boolean
  isLoggedIn?: boolean
  redirectTo?: string
  joinAction?: () => Promise<{error?: string} | void>

export function JoinEventButton({ alreadyJoined, isLoggedIn, redirectTo, joinAction }):
  const [isPending, startTransition] = useTransition()

  if alreadyJoined: return <div>이미 참여 중입니다</div>
  if !isLoggedIn: return <Link to login page />

  return (
    <button
      disabled={isPending || !joinAction}
      onClick={() => startTransition(async () => {
        const result = await joinAction?.()
        if result?.error: alert(result.error)
      })}
    >
      {isPending ? <Loader2 spinning /> : <UserPlus />}
      {isPending ? '처리 중...' : '참여하기'}
    </button>
  )

