'use client'
import { useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import Avatar, AvatarFallback, AvatarImage from shadcn
import Badge from shadcn

interface RealtimeParticipantsProps:
  eventId: string
  initialParticipants: ParticipantWithUser[]

export function RealtimeParticipants({ eventId, initialParticipants }):
  router = useRouter()

  useEffect(() => {
    supabase = createClient()
    channel = supabase
      .channel('event-participants-' + eventId)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'event_participants',
        filter: 'event_id=eq.' + eventId
      }, () => router.refresh())
      .subscribe()

    return () => supabase.removeChannel(channel)
  }, [eventId, router])

  return (
    <div>
      {initialParticipants.map(p => (
        <div key={p.id}>
          <Avatar> ... </Avatar>
          <span>{p.user.name}</span>
          {p.role === 'host' && <Badge>주최자</Badge>}
        </div>
      ))}
    </div>
  )

